/**
 * Bootstrap-smoke corpus entry (Wave A4): a REAL Betty-compiler helper,
 * copied VERBATIM from `open-source/gnosis/src/betti/s-duality-router.ts`
 * (`invertCoupling` — the S-duality inversion g → 1/g). The first betti
 * compiler source function to ride the certified Tier-A wasm lane as-is:
 * `aot_wasm::supports_wasm_for_export` claims it (scalar-v1 numeric class,
 * `Infinity` global constant included), and the pinned parity test lives
 * in `polyglot/tests/wasm_correctness.rs`
 * (`bootstrap_smoke_betti_invert_coupling`).
 *
 * Keep this byte-identical to the betti source body; the pinned test reads
 * the ORIGINAL file, so drift here only affects the coverage-corpus row.
 */
export function invertCoupling(g: number): number {
  if (g === 0) return Infinity;
  return 1 / g;
}
